class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // [EF9 Breaking] HasIndex now throws for Cosmos entities — removed.
        // Manage indexing via the container's indexing policy (Azure Portal / Bicep).

        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // [EF9 Breaking] Discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K docs use "Discriminator" — keep the old name so EF9 can read them
            // and so direct SQL queries (c.Discriminator) continue to work.
            entity.HasDiscriminator<string>("Discriminator");

            // [EF9 Breaking] id no longer includes the discriminator (was "Product|123", now "123").
            // Existing docs have the compound format — preserve it so FindAsync/point-reads work.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
